```javascript
function myReduce(arr, fn, initial) {
  let acc = initial;
  let start = 0;
  if (initial === undefined) {
    if (arr.length === 0) throw new TypeError("Reduce of empty array with no initial value");
    acc = arr[0];
    start = 1;
  }
  for (let i = start; i < arr.length; i++) acc = fn(acc, arr[i], i, arr);
  return acc;
}
```

